I'll help you swap 0.5 ETH to USDC on Arbitrum. Let me set up the SDK and execute the swap.

```typescript
const { GmxSdk } = require("@gmx-io/sdk");
const { createWalletClient, http } = require("viem");
const { privateKeyToAccount } = require("viem/accounts");
const { arbitrum } = require("viem/chains");

async function swapEthToUsdc() {
  // Setup account and wallet
  const account = privateKeyToAccount(process.env.PRIVATE_KEY);

  const walletClient = createWalletClient({
    account,
    chain: arbitrum,
    transport: http("https://arb1.arbitrum.io/rpc"),
  });

  const sdk = new GmxSdk({
    chainId: 42161,
    rpcUrl: "https://arb1.arbitrum.io/rpc",
    oracleUrl: "https://arbitrum-api.gmxinfra.io",
    subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
    account: account.address,
    walletClient,
  });

  // Fetch token data to resolve addresses
  const { tokensData } = await sdk.markets.getMarketsInfo();

  // Find WETH and USDC addresses
  // On Arbitrum, native ETH swaps use WETH
  const wethToken = Object.values(tokensData).find((t) => t.symbol === "WETH");
  const usdcToken = Object.values(tokensData).find((t) => t.symbol === "USDC");

  if (!wethToken || !usdcToken) {
    throw new Error("Could not find WETH or USDC token");
  }

  console.log("WETH address:", wethToken.address);
  console.log("USDC address:", usdcToken.address);

  // 0.5 ETH in wei (18 decimals)
  const fromAmount = 500000000000000000n; // 0.5 ETH

  console.log(`Swapping 0.5 ETH → USDC...`);
  console.log(`From: ${wethToken.address} (WETH)`);
  console.log(`To:   ${usdcToken.address} (USDC)`);
  console.log(`Amount: ${fromAmount} wei (0.5 ETH)`);

  // Execute the swap
  const result = await sdk.orders.swap({
    fromTokenAddress: wethToken.address,
    toTokenAddress: usdcToken.address,
    fromAmount,
    allowedSlippageBps: 100, // 1% slippage tolerance
    skipSimulation: true,
  });

  console.log("Swap order submitted!", result);
  return result;
}

swapEthToUsdc().catch(console.error);
```

**What this does:**

| Parameter | Value |
|-----------|-------|
| From | WETH (native ETH wrapper) |
| To | USDC |
| Amount | `500000000000000000n` (0.5 ETH, 18 decimals) |
| Slippage | 1% (`allowedSlippageBps: 100`) |
| Chain | Arbitrum (chainId 42161) |

**A few things to note:**

- **WETH vs ETH** — GMX routes ETH swaps through WETH internally. The SDK handles the wrap automatically when you use the WETH address.
- **Two-phase execution** — The swap order is submitted onchain, then a keeper executes it with fresh oracle prices (typically 1–5 seconds).
- **Execution fee** — A small ETH fee is charged to cover keeper gas costs. The SDK calculates and includes this automatically.
- **Slippage** — At 1%, if the received USDC would be more than 1% below the oracle price, the order cancels rather than executing at a bad price. Increase `allowedSlippageBps` (up to 500) if you're seeing cancellations.

Make sure `PRIVATE_KEY` is set in your environment before running.

