  const limitPrice = 2800n * 10n ** 30n;

  // ─── Place limit long order ──────────────────────────────────────────────
  // Paying 100 USDC (6 decimals) with 3x leverage
  // Order triggers when oracle price <= $2800 (limit buy = buy the dip)
  const tx = await sdk.orders.long({
    marketAddress,
    payTokenAddress: usdcToken.address,
    collateralTokenAddress: longTokenAddress, // WETH collateral for longs
    payAmount: 100_000000n,                   // 100 USDC (6 decimals)
    leverage: 30000n,                         // 3x leverage (basis points)
    limitPrice,                               // Triggers at or below $2800
    allowedSlippageBps: 100,                  // 1% slippage tolerance
    skipSimulation: true,
  });

  console.log("\n✅ Limit buy order submitted!");
  console.log("   Trigger price: $2,800");
  console.log("   Pay amount:    100 USDC");
