const { getDecreasePositionAmounts } = require("@gmx-io/sdk/utils/trade");
const { createWalletClient, http } = require("viem");
const { privateKeyToAccount } = require("viem/accounts");
const { arbitrum } = require("viem/chains");

async function openLongWithSLTP() {
  // ─── Setup ───────────────────────────────────────────────────────────────
  const account = privateKeyToAccount(process.env.PRIVATE_KEY);

  const sdk = new GmxSdk({
    chainId: 42161,
    rpcUrl: "https://arb1.arbitrum.io/rpc",
    oracleUrl: "https://arbitrum-api.gmxinfra.io",
    subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
    account: account.address,
    walletClient: createWalletClient({
      account,
      chain: arbitrum,
      transport: http("https://arb1.arbitrum.io/rpc"),
    }),
  });

  // ─── Resolve addresses ───────────────────────────────────────────────────
  const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

  const ethMarket = Object.values(marketsInfoData).find(
    (m) => tokensData[m.indexTokenAddress]?.symbol === "WETH" && !m.isSpotOnly
  );
  if (!ethMarket) throw new Error("ETH/USD market not found");

  const marketAddress = ethMarket.marketTokenAddress;
  const longTokenAddress = ethMarket.longTokenAddress;

  const usdcToken = Object.values(tokensData).find((t) => t.symbol === "USDC");
  if (!usdcToken) throw new Error("USDC not found");

  // Get current ETH price for SL/TP calculation (30 decimals)
  const ethToken = tokensData[longTokenAddress];
  const currentPrice = (ethToken.prices.minPrice + ethToken.prices.maxPrice) / 2n;

  // Convert to human-readable for display
  const currentPriceUsd = Number(currentPrice / 10n ** 24n) / 1_000_000n;
  console.log(`📈 Current ETH price: $${Number(currentPrice / 10n ** 27n)}`);

  // ─── Define SL/TP levels ─────────────────────────────────────────────────
  // Stop-loss: -10% from current price
  // Take-profit: +15% from current price
  const stopLossPrice = (currentPrice * 90n) / 100n;
  const takeProfitPrice = (currentPrice * 115n) / 100n;

  console.log(`🛑 Stop-loss price:   $${Number(stopLossPrice / 10n ** 27n)}`);
  console.log(`🎯 Take-profit price: $${Number(takeProfitPrice / 10n ** 27n)}`);

  // ─── Open Long Position ───────────────────────────────────────────────────
  console.log("\n⏳ Submitting long order...");
  const tx = await sdk.orders.long({
    marketAddress,
    payTokenAddress: usdcToken.address,
    collateralTokenAddress: longTokenAddress,
    payAmount: 200_000000n,   // $200 USDC
    leverage: 50000n,          // 5x
    allowedSlippageBps: 100,
    skipSimulation: true,
  });
  console.log("✅ Order submitted! Tx:", tx);

  // ─── Monitor until position appears ──────────────────────────────────────
  console.log("\n⏳ Waiting for keeper to execute (up to 120s)...");
  let position = null;

  for (let i = 0; i < 40; i++) {
    await new Promise((r) => setTimeout(r, 3000));
    process.stdout.write(`  Checking... (${(i + 1) * 3}s)\r`);

    const { marketsInfoData: freshMarkets, tokensData: freshTokens } =
      await sdk.markets.getMarketsInfo();

    const positionsInfo = await sdk.positions.getPositionsInfo({
      marketsInfoData: freshMarkets,
      tokensData: freshTokens,
      showPnlInLeverage: false,
    });

    position = Object.values(positionsInfo).find(
      (p) => p.marketAddress === marketAddress && p.isLong === true
    );

    if (position) {
      console.log("\n✅ Position confirmed open!");
      break;
    }
  }

  if (!position) {
    throw new Error("❌ Position did not appear within 120s — check the tx on Arbiscan");
  }

  // ─── Display position details ─────────────────────────────────────────────
  const entryPriceUsd = Number(position.entryPrice / 10n ** 27n);
  const sizeUsd = Number(position.sizeInUsd / 10n ** 30n);
  const collateralUsd = Number(position.collateralUsd / 10n ** 30n);
  const leverage = Number(position.leverage) / 10000;

  console.log("\n📊 Position Summary:");
  console.log(`   Size:       $${sizeUsd.toFixed(2)}`);
  console.log(`   Collateral: $${collateralUsd.toFixed(2)}`);
  console.log(`   Leverage:   ${leverage.toFixed(1)}x`);
  console.log(`   Entry:      $${entryPriceUsd.toFixed(2)}`);

  // ─── Place Stop-Loss ──────────────────────────────────────────────────────
  console.log("\n⏳ Placing stop-loss order...");

  // Re-fetch fresh data — prices go stale within seconds
  const { marketsInfoData: slMarkets, tokensData: slTokens } =
    await sdk.markets.getMarketsInfo();

  const slPositions = await sdk.positions.getPositionsInfo({
    marketsInfoData: slMarkets,
    tokensData: slTokens,
    showPnlInLeverage: false,
  });

  const slPosition = Object.values(slPositions).find(
    (p) => p.marketAddress === marketAddress && p.isLong === true
  );

  const slMarketInfo = slMarkets[slPosition.marketAddress];
  const slCollateralToken = slTokens[slPosition.collateralTokenAddress];
  const { minCollateralUsd, minPositionSizeUsd } =
    await sdk.positions.getPositionsConstants();
  const uiFeeFactor = await sdk.utils.getUiFeeFactor();

  const slDecreaseAmounts = getDecreasePositionAmounts({
    marketInfo: slMarketInfo,
    collateralToken: slCollateralToken,
    isLong: slPosition.isLong,
    position: slPosition,
    closeSizeUsd: slPosition.sizeInUsd,  // Full close on SL
    keepLeverage: false,
    userReferralInfo: undefined,
    minCollateralUsd,
