I'll help you adjust your ETH position leverage to 3x. Let me first check your current position to understand what needs to change.

**How leverage adjustment works on GMX V2:**
GMX doesn't have a direct "set leverage" operation. To change leverage, you either:
1. **Add collateral** (decrease leverage) — via a $0 size increase order with extra collateral
2. **Remove collateral** (increase leverage) — via a decrease order that withdraws collateral without closing
3. **Partially close** the position to reduce size while keeping collateral

Let me fetch your position details first.

```typescript
const { GmxSdk } = require("@gmx-io/sdk");
const { createWalletClient, createPublicClient, http } = require("viem");
const { privateKeyToAccount } = require("viem/accounts");
const { arbitrum } = require("viem/chains");

async function getEthPosition() {
  const account = privateKeyToAccount(process.env.PRIVATE_KEY);

  const sdk = new GmxSdk({
    chainId: 42161,
    rpcUrl: "https://arb1.arbitrum.io/rpc",
    oracleUrl: "https://arbitrum-api.gmxinfra.io",
    subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
    account: account.address,
    walletClient: createWalletClient({
      account,
      chain: arbitrum,
      transport: http("https://arb1.arbitrum.io/rpc"),
    }),
  });

  const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

  const positionsInfo = await sdk.positions.getPositionsInfo({
    marketsInfoData,
    tokensData,
    showPnlInLeverage: false,
  });

  // Find ETH positions (long or short)
  const ethPositions = Object.values(positionsInfo).filter((p) => {
    const indexToken = tokensData[marketsInfoData[p.marketAddress]?.indexTokenAddress];
    return indexToken?.symbol === "WETH";
  });

  if (ethPositions.length === 0) {
    console.log("No ETH positions found.");
    return;
  }

  for (const pos of ethPositions) {
    const currentLeverageBps = pos.leverage; // in basis points
    const currentLeverageX = Number(currentLeverageBps) / 10000;
    const targetLeverageX = 3.0;
    const targetLeverageBps = BigInt(Math.round(targetLeverageX * 10000));

    console.log(`\nETH ${pos.isLong ? "Long" : "Short"} Position:`);
    console.log(`  Size (USD):       $${(Number(pos.sizeInUsd) / 1e30).toFixed(2)}`);
    console.log(`  Collateral (USD): $${(Number(pos.collateralUsd) / 1e30).toFixed(2)}`);
    console.log(`  Current leverage: ${currentLeverageX.toFixed(2)}x`);
    console.log(`  Target leverage:  ${targetLeverageX}x`);

    if (Math.abs(currentLeverageX - targetLeverageX) < 0.05) {
      console.log("  ✓ Already at ~3x leverage, no adjustment needed.");
      continue;
    }

    if (currentLeverageX > targetLeverageX) {
      // Need to ADD collateral to reduce leverage
      // Required collateral = sizeInUsd / targetLeverage
      const requiredCollateralUsd = pos.sizeInUsd / targetLeverageBps * 10000n;
      const collateralToAddUsd = requiredCollateralUsd - pos.collateralUsd;
      console.log(`  Action: ADD ~$${(Number(collateralToAddUsd) / 1e30).toFixed(2)} collateral`);
    } else {
      // Need to REMOVE collateral to increase leverage
      const requiredCollateralUsd = pos.sizeInUsd / targetLeverageBps * 10000n;
      const collateralToRemoveUsd = pos.collateralUsd - requiredCollateralUsd;
      console.log(`  Action: REMOVE ~$${(Number(collateralToRemoveUsd) / 1e30).toFixed(2)} collateral`);
    }
  }
}

getEthPosition().catch(console.error);
```

