```typescript
const { GmxSdk } = require("@gmx-io/sdk");

const sdk = new GmxSdk({
  chainId: 42161,
  rpcUrl: "https://arb1.arbitrum.io/rpc",
  oracleUrl: "https://arbitrum-api.gmxinfra.io",
  subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
});

async function analyzeBTC() {
  const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

  // Find BTC/USD market
  const btcMarket = Object.values(marketsInfoData).find(
    (m) => tokensData[m.indexTokenAddress]?.symbol === "BTC" && !m.isSpotOnly
  );

  if (!btcMarket) {
    console.log("BTC market not found");
    return;
  }

  const btcToken = tokensData[btcMarket.indexTokenAddress];
  const midPrice = (btcToken.prices.minPrice + btcToken.prices.maxPrice) / 2n;
  // Prices are 30-decimal scaled
  const priceUsd = Number(midPrice) / 1e30;

  const longOI = btcMarket.longInterestUsd;
  const shortOI = btcMarket.shortInterestUsd;
  const totalOI = longOI + shortOI;
  const longPct = totalOI > 0n ? Number(longOI * 10000n / totalOI) / 100 : 0;
  const shortPct = 100 - longPct;

  const longPool = btcMarket.longPoolAmount;
  const shortPool = btcMarket.shortPoolAmount;

  // Funding: positive = longs pay shorts, negative = shorts pay longs
  const fundingPerSecond = btcMarket.fundingFactorPerSecond;
  const longsPayShorts = btcMarket.longsPayShorts;
  const fundingAprBps = Number(fundingPerSecond) * 3600 * 24 * 365 / 1e26 * 10000;

  // Borrowing rates (annualized approximation)
  const borrowLongApr = Number(btcMarket.borrowingFactorPerSecondForLongs) * 3600 * 24 * 365 / 1e26 * 100;
  const borrowShortApr = Number(btcMarket.borrowingFactorPerSecondForShorts) * 3600 * 24 * 365 / 1e26 * 100;

  console.log("=== BTC/USD Market Analysis ===");
  console.log(`Market: ${btcMarket.marketTokenAddress}`);
  console.log(`\nPrice:`);
  console.log(`  Min: $${(Number(btcToken.prices.minPrice) / 1e30).toLocaleString()}`);
  console.log(`  Max: $${(Number(btcToken.prices.maxPrice) / 1e30).toLocaleString()}`);
  console.log(`  Mid: $${priceUsd.toLocaleString()}`);
  console.log(`  Spread: $${((Number(btcToken.prices.maxPrice - btcToken.prices.minPrice)) / 1e30).toFixed(2)}`);

  console.log(`\nOpen Interest:`);
  console.log(`  Longs: $${(Number(longOI) / 1e30).toLocaleString()} (${longPct.toFixed(1)}%)`);
  console.log(`  Shorts: $${(Number(shortOI) / 1e30).toLocaleString()} (${shortPct.toFixed(1)}%)`);
  console.log(`  Total: $${(Number(totalOI) / 1e30).toLocaleString()}`);
  console.log(`  Skew: ${longPct > shortPct ? "LONG-heavy" : "SHORT-heavy"} by ${Math.abs(longPct - shortPct).toFixed(1)}%`);

  console.log(`\nPool Liquidity:`);
  console.log(`  Long pool (BTC): ${(Number(longPool) / 1e8).toFixed(4)} BTC`);
  console.log(`  Short pool (USDC): $${(Number(shortPool) / 1e6).toLocaleString()}`);

  console.log(`\nFunding Rate:`);
  console.log(`  Direction: ${longsPayShorts ? "Longs pay Shorts" : "Shorts pay Longs"}`);
  console.log(`  Rate (annualized ~): ${Math.abs(fundingAprBps).toFixed(4)}% APR`);

  console.log(`\nBorrowing Rate (annualized ~):`);
  console.log(`  Long positions: ${borrowLongApr.toFixed(4)}% APR`);
  console.log(`  Short positions: ${borrowShortApr.toFixed(4)}% APR`);

  console.log(`\nFee Structure:`);
  console.log(`  Position fee (balanced): ${Number(btcMarket.positionFeeFactorForPositiveImpact) / 1e26}%`);
  console.log(`  Position fee (imbalancing): ${Number(btcMarket.positionFeeFactorForNegativeImpact) / 1e26}%`);

  console.log(`\nCapacity:`);
  console.log(`  Max long OI: $${(Number(btcMarket.maxOpenInterestForLongs) / 1e30).toLocaleString()}`);
  console.log(`  Max short OI: $${(Number(btcMarket.maxOpenInterestForShorts) / 1e30).toLocaleString()}`);
  console.log(`  Long OI utilization: ${(Number(longOI) * 100 / Number(btcMarket.maxOpenInterestForLongs)).toFixed(1)}%`);
  console.log(`  Short OI utilization: ${(Number(shortOI) * 100 / Number(btcMarket.maxOpenInterestForShorts)).toFixed(1)}%`);
}

analyzeBTC().catch(console.error);
```

Here's what the data shows and how to interpret it for a directional call:

---

## What the Metrics Tell You

### Price Spread
The min/max spread reflects oracle confidence. A tight spread (< $10) means clean execution. A wide spread means higher effective slippage on entry.

### Open Interest Skew
This is the most actionable signal from GMX data:
- **Long-heavy (>60% longs):** The crowd is positioned long. Contrarian read = short pressure building. Also means longs pay funding, making shorts cheaper to hold.
- **Short-heavy (>60% shorts):** Opposite — shorts pay funding, longs get paid to hold.
- **Balanced (~50/50):** No strong crowd lean; lower funding costs either way.

### Funding Rate
- If **longs pay shorts**: holding a long costs you; holding a short earns you. Favors shorts on a cost basis.
- If **shorts pay longs**: holding a short costs you; holding a long earns you. Favors longs on a cost basis.

### Borrowing Rate
Both sides pay borrowing. Compare long vs. short borrow rates — the cheaper side has a structural cost advantage.

---

## What GMX Data Can't Tell You

This is important: **GMX market data is not a price prediction tool.** It tells you positioning and costs, not direction. For a genuine long/short call you also need:

- **Price action / technicals** — trend, key S/R levels, recent structure
- **Macro context** — Fed policy, risk-on/off sentiment, BTC dominance
- **On-chain signals** — exchange flows, whale accumulation, funding across all venues (not just GMX)
- **Broader derivatives data** — Binance/Bybit perpetual funding, options

