```typescript
const { GmxSdk } = require("@gmx-io/sdk");
const { getDecreasePositionAmounts } = require("@gmx-io/sdk/utils/trade");
const { createWalletClient, http } = require("viem");
const { privateKeyToAccount } = require("viem/accounts");
const { arbitrum } = require("viem/chains");

const account = privateKeyToAccount(process.env.PRIVATE_KEY);
const sdk = new GmxSdk({
  chainId: 42161,
  rpcUrl: "https://arb1.arbitrum.io/rpc",
  oracleUrl: "https://arbitrum-api.gmxinfra.io",
  subsquidUrl: "https://gmx.squids.live/gmx-synthetics-arbitrum:prod/api/graphql",
  account: account.address,
  walletClient: createWalletClient({
    account,
    chain: arbitrum,
    transport: http("https://arb1.arbitrum.io/rpc"),
  }),
});

// Step 1: Fetch fresh market + position data
const { marketsInfoData, tokensData } = await sdk.markets.getMarketsInfo();

const positionsInfo = await sdk.positions.getPositionsInfo({
  marketsInfoData,
  tokensData,
  showPnlInLeverage: false,
});

// Step 2: Find the ETH long position
const ethLong = Object.values(positionsInfo).find((p) => {
  const indexToken = tokensData[marketsInfoData[p.marketAddress]?.indexTokenAddress];
  return (indexToken?.symbol === "WETH" || indexToken?.symbol === "ETH") && p.isLong === true;
});

if (!ethLong) {
  throw new Error("No ETH long position found.");
}

console.log("Found ETH long position:", {
  market: ethLong.marketAddress,
  sizeUsd: (ethLong.sizeInUsd / BigInt(1e30)).toString() + " USD",
  collateral: (ethLong.collateralAmount / BigInt(1e18)).toString() + " tokens",
  entryPrice: (ethLong.entryPrice / BigInt(1e30)).toString() + " USD",
  pnl: (ethLong.pnl / BigInt(1e30)).toString() + " USD",
  leverage: (ethLong.leverage / BigInt(1e4)).toString() + "x",
});

// Step 3: Compute decrease amounts for full close
const marketInfo = marketsInfoData[ethLong.marketAddress];
const collateralToken = tokensData[ethLong.collateralTokenAddress];
const { minCollateralUsd, minPositionSizeUsd } = await sdk.positions.getPositionsConstants();
const uiFeeFactor = await sdk.utils.getUiFeeFactor();

const decreaseAmounts = getDecreasePositionAmounts({
  marketInfo,
  collateralToken,
  isLong: ethLong.isLong,
  position: ethLong,
  closeSizeUsd: ethLong.sizeInUsd, // Full close
  keepLeverage: false,
  userReferralInfo: undefined,
  minCollateralUsd,
  minPositionSizeUsd,
  uiFeeFactor,
  isSetAcceptablePriceImpactEnabled: false,
});

// Step 4: Submit the close order
await sdk.orders.createDecreaseOrder({
  marketInfo,
  marketsInfoData,
  tokensData,
  isLong: ethLong.isLong,
  allowedSlippage: 300, // 3% slippage tolerance
  decreaseAmounts,
  collateralToken,
});

console.log("✅ Close order submitted. Keeper will execute in ~1–30 seconds.");
```

This script will:

1. **Fetch fresh data** — prices are fetched right before closing to ensure the `acceptablePrice` is current (stale prices cause keeper rejection)
2. **Find your ETH long** — searches all positions for an ETH/WETH long
3. **Compute close amounts** — uses `getDecreasePositionAmounts` to calculate the full close parameters
4. **Submit the order** — sends a `MarketDecrease` order with 3% slippage tolerance

The keeper will execute it within a few seconds. If you want to close only a **partial** amount, replace `closeSizeUsd: ethLong.sizeInUsd` with a smaller value (e.g., `ethLong.sizeInUsd / 2n` for 50%).

